+
+type Buffer = { commands: Command[] };
+export type DeferredState = { buffers: Buffer[]; flushing: boolean; reserved: Set<Entity> };
+
+export const createDeferredState = (): DeferredState => ({ buffers: [{ commands: [] }], flushing: false, reserved: new Set() });
+const current = (world: World) => world[$internal].deferred.buffers.at(-1)!;
+const commandsFor = (world: World) => world[$internal].deferred.buffers.flatMap((buffer) => buffer.commands);
+
+export function beginDeferredScope(world: World) { world[$internal].deferred.buffers.push({ commands: [] }); }
+export function endDeferredScope(world: World) {
+    const state = world[$internal].deferred;
+    const buffer = state.buffers.at(-1)!;
+    flushBuffer(world, buffer);
+    state.buffers.pop();
+}
+
+export function deferredSpawn(world: World, traits: ConfigurableTrait[]): Entity {
+    const index = world[$internal].entityIndex;
+    const entity = packEntity(index.worldId, 0, index.maxId++);
+    world[$internal].deferred.reserved.add(entity);
+    current(world).commands.push({ type: 'spawn', entity, traits });
+    return entity;
+}
+export function deferredDestroy(world: World, entity: Entity) { current(world).commands.push({ type: 'destroy', entity }); }
+export function deferredAdd(world: World, entity: Entity, traits: ConfigurableTrait[]) { current(world).commands.push({ type: 'add', entity, traits }); }
+export function deferredRemove(world: World, entity: Entity, traits: (Trait | RelationPair)[]) { current(world).commands.push({ type: 'remove', entity, traits }); }
+export function deferredAddExclusive(world: World, entity: Entity, pairs: RelationPair[]) { current(world).commands.push({ type: 'exclusive', entity, pairs }); }
+export function hasDeferredCommands(world: World, entity?: Entity) {
+    return commandsFor(world).some((command) => entity === undefined || command.entity === entity);
+}
+
+export function flushDeferred(world: World) { flushBuffer(world, current(world)); }
+
+function flushBuffer(world: World, buffer: Buffer) {
+    const state = world[$internal].deferred;
+    if (state.flushing || buffer.commands.length === 0) return;
+    state.flushing = true;
+    try {
+        // A spawn immediately destroyed in its own buffer is entirely invisible.
+        const cancelled = new Set<Entity>();
+        for (const command of buffer.commands) {
+            if (command.type === 'destroy' && buffer.commands.some((c) => c.type === 'spawn' && c.entity === command.entity)) cancelled.add(command.entity);
+        }
+        for (const command of buffer.commands) {
+            if (cancelled.has(command.entity)) continue;
+            if (command.type === 'spawn') {
+                if (state.reserved.delete(command.entity)) createReservedEntity(world, command.entity, ...command.traits);
+                continue;
+            }
+            if (state.reserved.has(command.entity) || !world.has(command.entity)) continue;
+            if (command.type === 'destroy') {
+                // The world entity may not be destroyed through a deferred command.
+                if (command.entity === world[$internal].worldEntity) throw new Error('Koota: The world entity cannot be destroyed by a deferred command.');
+                destroyEntity(world, command.entity);
+            } else if (command.type === 'add') {
+                addReplacingValues(world, command.entity, command.traits);
+            } else if (command.type === 'remove') {
+                removeTrait(world, command.entity, ...command.traits);
+            } else {
+                for (const pair of command.pairs) {
+                    const relation = pair[$internal].relation;
+                    removeTrait(world, command.entity, relation('*'));
+                    if (pair[$internal].target !== '*') addTrait(world, command.entity, pair);
+                }
+            }
+        }
+    } finally {
+        for (const command of buffer.commands) if (command.type === 'spawn') state.reserved.delete(command.entity);
+        buffer.commands.length = 0;
+        state.flushing = false;
+    }
+}
+
+function addReplacingValues(world: World, entity: Entity, traits: ConfigurableTrait[]) {
+    for (const config of traits) {
+        if (isRelationPair(config)) {
+            const target = config[$internal].target;
+            addTrait(world, entity, config);
+            if (typeof target === 'number' && config[$internal].params && hasRelationPair(world, entity, config)) setTrait(world, entity, config, config[$internal].params, false);
+        } else {
+            const trait = Array.isArray(config) ? config[0] : config;
+            addTrait(world, entity, config);
+            if (Array.isArray(config) && hasTrait(world, entity, trait)) setTrait(world, entity, trait, config[1], false);
+        }
+    }
+}
+
+export function deferredHas(world: World, entity: Entity, trait: Trait | RelationPair): boolean | undefined {
+    if (!hasDeferredCommands(world, entity) && !world[$internal].deferred.reserved.has(entity)) return undefined;
+    let alive = world.has(entity) || world[$internal].deferred.reserved.has(entity);
+    let present = isRelationPair(trait) ? hasRelationPair(world, entity, trait) : hasTrait(world, entity, trait as Trait);
+    for (const command of commandsFor(world)) {
+        if (command.entity !== entity) continue;
+        if (command.type === 'spawn') alive = true;
+        if (command.type === 'destroy') alive = false;
+        if (!alive) continue;
+        if (command.type === 'add') for (const config of command.traits) {
+            if (isRelationPair(trait) && isRelationPair(config) && samePair(config, trait)) present = true;
+            else if (!isRelationPair(trait) && !isRelationPair(config) && (Array.isArray(config) ? config[0] : config) === trait) present = true;
+        }
+        if (command.type === 'remove') for (const removed of command.traits) {
+            if (isRelationPair(trait) && isRelationPair(removed) && (samePair(removed, trait) || removed[$internal].target === '*')) present = false;
+            else if (!isRelationPair(trait) && removed === trait) present = false;
+        }
+        if (command.type === 'exclusive' && isRelationPair(trait)) for (const pair of command.pairs) {
+            if (pair[$internal].relation === trait[$internal].relation) present = pair[$internal].target !== '*' && samePair(pair, trait);
+        }
+    }
+    return alive && present;
+}
+
+export function deferredGet(world: World, entity: Entity, trait: Trait | RelationPair): any {
+    const has = deferredHas(world, entity, trait);
+    if (has === undefined) return undefined;
+    if (!has) return undefined;
+    let value = getTrait(world, entity, trait as any);
+    for (const command of commandsFor(world)) if (command.entity === entity && command.type === 'add') {
+        for (const config of command.traits) {
+            if (isRelationPair(trait) && isRelationPair(config) && samePair(config, trait)) value = config[$internal].params ?? value;
+            if (!isRelationPair(trait) && !isRelationPair(config) && (Array.isArray(config) ? config[0] : config) === trait) value = Array.isArray(config) ? config[1] : value;
+        }
+    }
+    return value;
+}
+function samePair(a: RelationPair, b: RelationPair) { return a[$internal].relation === b[$internal].relation && a[$internal].target === b[$internal].target; }
