+    beforeEach(() => universe.reset());
+
+    it('projects pending trait state and replaces later values', () => {
+        const Position = trait({ x: 0 });
+        const world = createWorld();
+        const entity = world.spawn();
+
+        world.deferred.add(entity, Position({ x: 1 }));
+        world.deferred.add(entity, Position({ x: 2 }));
+
+        expect(entity.has(Position)).toBe(true);
+        expect(entity.get(Position)).toEqual({ x: 2 });
+        expect(world.query(Position)).toHaveLength(0);
+        world.deferred.flush();
+        expect(entity.get(Position)).toEqual({ x: 2 });
+    });
+
+    it('flushes a query scope at updateEach exit', () => {
+        const Marker = trait();
+        const world = createWorld();
+        const entity = world.spawn(Marker);
+        world.query(Marker).updateEach((_, subject) => world.deferred.destroy(subject));
+        expect(world.has(entity)).toBe(false);
+    });
+
+    it('nullifies a spawn destroyed in the same buffer', () => {
+        const Marker = trait();
+        const world = createWorld();
